/* ════════════════════════════════════════
   LIGHTBOX — with multi-image per project
════════════════════════════════════════ */
.lightbox-overlay {
  position: fixed; inset: 0;
  background: rgba(10,10,20,0.85);
  backdrop-filter: blur(12px); -webkit-backdrop-filter: blur(12px);
  z-index: 9999;
  display: flex; align-items: center; justify-content: center;
  padding: 1.5rem;
  opacity: 0; pointer-events: none;
  transition: opacity 0.35s ease;
}
.lightbox-overlay.open { opacity: 1; pointer-events: all; }
.lightbox-modal {
  background: var(--card-bg); border-radius: 24px;
  width: 100%; max-width: 940px; max-height: 92vh;
  overflow: hidden; display: flex; flex-direction: column;
  box-shadow: 0 40px 100px rgba(0,0,0,0.4);
  transform: scale(0.93) translateY(20px);
  transition: transform 0.4s cubic-bezier(0.34,1.56,0.64,1);
}
.lightbox-overlay.open .lightbox-modal { transform: scale(1) translateY(0); }

/* Browser chrome */
.lb-chrome {
  padding: 11px 18px; background: var(--bg2);
  border-bottom: 1px solid var(--border);
  display: flex; align-items: center; gap: 10px; flex-shrink: 0;
}
.lb-chrome-dots { display: flex; gap: 5px; }
.lb-chrome-dot { width: 10px; height: 10px; border-radius: 50%; cursor: pointer; transition: transform 0.15s; }
.lb-chrome-dot:hover { transform: scale(1.15); }
.lb-chrome-url { flex: 1; background: var(--card-bg); border: 1px solid var(--border); border-radius: 100px; padding: 5px 14px; font-size: 0.78rem; color: var(--text-muted); display: flex; align-items: center; gap: 6px; }
.lb-lock { color: var(--green); flex-shrink: 0; }
.lb-chrome-actions { display: flex; gap: 0.5rem; }
.lb-btn { background: none; border: 1.5px solid var(--border); border-radius: 100px; color: var(--text-muted); font-size: 0.76rem; padding: 0.3rem 0.85rem; cursor: pointer; transition: all 0.2s; font-family: 'Plus Jakarta Sans', sans-serif; display: flex; align-items: center; gap: 0.3rem; text-decoration: none; font-weight: 600; }
.lb-btn:hover { border-color: var(--violet); color: var(--violet); }
.lb-close-btn { background: var(--bg3); border: 1.5px solid var(--border); border-radius: 50%; width: 30px; height: 30px; cursor: pointer; color: var(--text-muted); display: flex; align-items: center; justify-content: center; transition: all 0.2s; flex-shrink: 0; }
.lb-close-btn:hover { background: #ffeded; border-color: #f87171; color: #f87171; }

.lb-body { flex: 1; overflow: hidden; display: flex; flex-direction: column; min-height: 0; }

/* ── Image gallery area ── */
.lb-gallery {
  position: relative;
  height: 360px; flex-shrink: 0;
  overflow: hidden;
}
.lb-slides {
  display: flex;
  width: 100%; height: 100%;
  transition: transform 0.45s cubic-bezier(0.25,0.46,0.45,0.94);
  will-change: transform;
}
.lb-slide {
  flex: 0 0 100%;
  height: 100%;
  position: relative;
  overflow: hidden;
}
.lb-slide-label {
  position: absolute;
  top: 12px; left: 50%; transform: translateX(-50%);
  background: rgba(0,0,0,0.45);
  color: rgba(255,255,255,0.9);
  font-size: 0.7rem; font-weight: 600;
  padding: 0.22rem 0.75rem;
  border-radius: 100px;
  backdrop-filter: blur(4px);
  z-index: 5;
  white-space: nowrap;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

/* Gallery nav */
.lb-nav-prev, .lb-nav-next {
  position: absolute; top: 50%; transform: translateY(-50%);
  width: 46px; height: 46px; border-radius: 50%;
  background: rgba(255,255,255,0.92);
