.lb-nav-prev:disabled, .lb-nav-next:disabled { opacity: 0.35; cursor: not-allowed; }
.lb-nav-prev:disabled:hover, .lb-nav-next:disabled:hover { background: rgba(255,255,255,0.92); color: var(--text); transform: translateY(-50%); }

/* Gallery dots */
.lb-gallery-dots {
  position: absolute; bottom: 14px; left: 50%; transform: translateX(-50%);
  display: flex; gap: 6px; z-index: 10;
}
.lb-gallery-dot {
  width: 6px; height: 6px; border-radius: 100px;
