.lb-info-right { display: flex; gap: 0.75rem; align-items: center; flex-shrink: 0; }
.lb-visit-btn { background: var(--accent); color: #fff; padding: 0.62rem 1.4rem; border-radius: 100px; text-decoration: none; font-weight: 700; font-size: 0.84rem; white-space: nowrap; display: inline-flex; align-items: center; gap: 0.4rem; transition: background 0.2s, transform 0.2s; }
.lb-visit-btn:hover { background: var(--violet); transform: translateY(-1px); }

/* Thumbnails strip (projects) */
.lb-thumbs {
  display: flex; gap: 8px;
  padding: 0.9rem 1.75rem;
