}
.lb-thumb.active { border-color: var(--violet); }
.lb-thumb:hover { border-color: rgba(91,79,207,0.4); transform: scale(1.06); }
.lb-thumb-inner { width: 100%; height: 100%; border-radius: 6px; overflow: hidden; }
.lb-thumb-label {
