  background: rgba(0,0,0,0.45);
  color: rgba(255,255,255,0.9);
  font-size: 7px; text-align: center; padding: 2px;
  font-weight: 600; letter-spacing: 0.03em;
}

/* ── RESPONSIVE ── */
@media (max-width: 900px) { .about-grid { grid-template-columns: 1fr; gap: 3rem; } }
@media (max-width: 768px) {
  nav { padding: 1rem 1.5rem; } .nav-links { display: none; }
  section { padding: 5rem 1.5rem; } .hero { padding: 7rem 1.5rem 4rem; }
