  color: #fff; margin-bottom: 0.4rem; letter-spacing: -0.01em;
}
.cs-gallery-cta p { font-size: 0.8rem; color: rgba(255,255,255,0.5); margin-bottom: 1.1rem; line-height: 1.6; }
.cs-gallery-cta a {
  display: inline-flex; align-items: center; gap: 0.45rem;
  background: #fff; color: #302b63; padding: 0.6rem 1.4rem;
  border-radius: 100px; text-decoration: none; font-weight: 700; font-size: 0.83rem;
  transition: all 0.2s;
}
.cs-gallery-cta a:hover { transform: translateY(-2px); opacity: 0.92; }

/* Image zoom overlay */
.cs-zoom-bg {
  position: fixed; inset: 0; z-index: 99999;
  background: rgba(0,0,0,0.93); backdrop-filter: blur(8px);
  display: flex; align-items: center; justify-content: center; padding: 2rem;
  opacity: 0; pointer-events: none; transition: opacity 0.22s;
}
.cs-zoom-bg.open { opacity: 1; pointer-events: all; }
.cs-zoom-img {
  max-width: 100%; max-height: 100%; border-radius: 10px;
  box-shadow: 0 40px 100px rgba(0,0,0,0.6);
}
.cs-zoom-close {
  position: absolute; top: 1.25rem; right: 1.25rem;
  width: 40px; height: 40px; border-radius: 50%;
  background: rgba(255,255,255,0.1); border: 1px solid rgba(255,255,255,0.18);
  color: #fff; cursor: pointer; display: flex; align-items: center; justify-content: center;
  transition: all 0.2s; backdrop-filter: blur(6px);
}
.cs-zoom-close:hover { background: rgba(239,68,68,0.28); border-color: rgba(239,68,68,0.4); }

/* ── RESPONSIVE ── */
@media (max-width: 900px) {
  .about-grid { grid-template-columns: 1fr; gap: 3rem; }
  .cs-sidebar { width: 290px; }
}
@media (max-width: 768px) {
  nav { padding: 1rem 1.5rem; } .nav-links { display: none; }
  section { padding: 5rem 1.5rem; } .hero { padding: 7rem 1.5rem 4rem; }
  .hero-stats { gap: 1.5rem; } footer { padding: 1.5rem; }
  .work-card { flex: 0 0 310px; } .work-mockup { height: 190px; }
  .about-highlight-cards { grid-template-columns: 1fr 1fr; }
  .hero-deco1, .hero-deco2, .hero-deco3 { display: none; }
  .cs-modal { flex-direction: column; }
  .cs-sidebar { width: 100%; max-height: 45vh; }
  .cs-thumbs-grid { grid-template-columns: repeat(5, 1fr); }
  .cs-img-grid { grid-template-columns: 1fr 1fr; }
}
@media (max-width: 480px) {
  .work-card { flex: 0 0 285px; } .cta-box { padding: 3rem 1.5rem; }
  .cs-img-grid { grid-template-columns: 1fr; }
  .cs-sidebar { max-height: 50vh; }
}

